// 定义一组共享 shape 属性的类型
type Circle = {
  kind: "circle";
  radius: number;
};

type Rectangle = {
  kind: "rectangle";
  width: number;
  height: number;
};

type Triangle = {
  kind: "triangle";
  base: number;
  height: number;
};

// 联合类型：通过 kind 区分
type Shape = Circle | Rectangle | Triangle;

// 使用时，TypeScript 能根据 kind 收窄类型
function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      // 这里 shape 自动收窄为 Circle，可以安全访问 radius
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return (shape.base * shape.height) / 2;
  }
}

// 穷举检查：新增类型时漏写 case 会编译报错
function areaExhaustive(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return (shape.base * shape.height) / 2;
    default:
      // shape 在这里是 never 类型，确保所有 case 都已覆盖
      const _exhaustive: never = shape;
      return _exhaustive;
  }
}
```

**核心要点**：

- `kind` 是字符串字面量类型（`"circle"` | `"rectangle"` | `"triangle"`），作为判别属性（discriminant）
- switch 进入某个 case 后，TypeScript 自动把类型收窄到对应的具体类型
- 用 `never` 做 exhaustiveness check，新增成员时如果漏写 case 会在 default 处报编译错误
- 实际项目里常用于处理 API 响应（`{ status: "loading" }` | `{ status: "success", data: T }` | `{ status: "error", error: Error }`）、Redux action、表单字段配置等场景

